class RecipeFilter{constructor({listSelector,itemSelector,categoryAttr="categories",ingredientAttr="ingredients",statusSelector=null,noResultsSelector=null}){this.listEl=document.querySelector(listSelector);if(!this.listEl){throw new Error(`RecipeFilter: Container "${ listSelector }" nicht gefunden.`)}this.itemSelector=itemSelector;this.categoryAttr=categoryAttr;this.ingredientAttr=ingredientAttr;this.statusEl=statusSelector?document.querySelector(statusSelector):null;this.noResultsEl=noResultsSelector?document.querySelector(noResultsSelector):null;this.activeCategories=new Set();this.activeIngredients=new Set();this.items=Array.from(this.listEl.querySelectorAll(this.itemSelector))}_readAttrSet(el,attrName){const raw=el.dataset[attrName]||"";return new Set(raw.split(",").map((v)=>v.trim().toLowerCase()).filter(Boolean))}matches(el){const itemCategories=this._readAttrSet(el,this.categoryAttr);const itemIngredients=this._readAttrSet(el,this.ingredientAttr);const categoryOk=this.activeCategories.size===0||[...this.activeCategories].some((c)=>itemCategories.has(c));const ingredientOk=this.activeIngredients.size===0||[...this.activeIngredients].some((i)=>itemIngredients.has(i));return categoryOk&&ingredientOk}setFilters({categories=[],ingredients=[]}={}){this.activeCategories=new Set(categories.map((c)=>c.toLowerCase()));this.activeIngredients=new Set(ingredients.map((i)=>i.toLowerCase()));this.apply()}reset(){this.activeCategories.clear();this.activeIngredients.clear();this.apply()}apply(){let visibleCount=0;this.items.forEach((el)=>{const isMatch=this.matches(el);el.hidden=!isMatch;if(isMatch){visibleCount+=1}});if(this.noResultsEl){this.noResultsEl.hidden=visibleCount!==0}this._announce(visibleCount);return visibleCount}_announce(count){if(!this.statusEl){return}const total=this.items.length;this.statusEl.textContent=count===total?`${ count } von ${ total } Rezepten werden angezeigt`:`${ count } von ${ total } Rezepten werden angezeigt (gefiltert)`}}